from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector
qc = QuantumCircuit(2)
qc.x(0)
d = Statevector.from_instruction(qc).probabilities_dict()
obs = {str(k): round(float(v), 6) for k, v in d.items()}
true_key = max(obs, key=obs.get)
claims = {"D": "01", "A": "10", "B": "11", "C": "00"}
evidence = {}
proven = []
for k, key in claims.items():
    m = (obs.get(key, 0.0) == 1.0)
    evidence[k] = f"probabilities_dict() = {obs}; option {k} claims '{key}':1.0 -> match={m}"
    if m:
        proven.append(k)
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"dict": obs, "certain_outcome": true_key}})
